import{_ as a,o as i,c as t,ae as n}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"iOS Troubleshooting","description":"","frontmatter":{"title":"iOS Troubleshooting","slug":"ios-troubleshooting"},"headers":[],"relativePath":"developer-hub/ios-troubleshooting.md","filePath":"developer-hub/ios-troubleshooting.md"}'),o={name:"developer-hub/ios-troubleshooting.md"};function r(s,e,l,h,d,p){return i(),t("div",null,[...e[0]||(e[0]=[n('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>This guide lists out some of the most common challenges we see customers run into when trying to integrate the Branch iOS SDK.</p><p>To integrate the Branch iOS SDK, follow the steps in our iOS SDK Basic Integration <a href="./ios-basic-integration.html">guide</a>.</p><h2 id="scenarios" tabindex="-1">Scenarios <a class="header-anchor" href="#scenarios" aria-label="Permalink to &quot;Scenarios&quot;">​</a></h2><h3 id="x-twitter-webviews-do-not-redirect" tabindex="-1">X (Twitter) WebViews do not redirect <a class="header-anchor" href="#x-twitter-webviews-do-not-redirect" aria-label="Permalink to &quot;X (Twitter) WebViews do not redirect&quot;">​</a></h3><p>Universal Links and URI schemes do not redirect from X’s in-app browser properly. To work around this, we recommend using an <a href="https://help.branch.io/marketer-hub/docs/enable-deepviews" target="_blank" rel="noreferrer">active Deepview</a>. Instead of an automatic redirect, users are shown a landing page with a button to open your app. This ensures a consistent experience for users coming from X.</p><h3 id="app-does-not-open" tabindex="-1">App does not open <a class="header-anchor" href="#app-does-not-open" aria-label="Permalink to &quot;App does not open&quot;">​</a></h3><p>If your app is not opening when you click a Branch Deep Link, confirm that:</p><ol><li>The Branch iOS SDK has been <a href="./ios-basic-integration.html">integrated</a> into your app <a href="./ios-testing.html#testing-tools">successfully</a>.</li><li>Universal Links are enabled on the device (can only be disabled on iOS 9 and iOS 10). The iOS SDK Testing <a href="./ios-testing.html#test-deep-linking">guide</a> has steps on testing a Branch Deep Link, which will re-enable Universal Links on the device.</li><li>No issues related to the actual <a href="./creating-a-deep-link.html">creation</a> of the Branch Deep Link.</li><li>Your website is <a href="https://branch.io/resources/aasa-validator/" target="_blank" rel="noreferrer">properly configured</a> for Universal Links.</li></ol><h3 id="link-does-not-pass-data" tabindex="-1">Link does not pass data <a class="header-anchor" href="#link-does-not-pass-data" aria-label="Permalink to &quot;Link does not pass data&quot;">​</a></h3><p>If Branch Deep Link data is not getting funneled to your app, confirm that:</p><ol><li>You are not having issues related to the <a href="./ios-troubleshooting.html#app-does-not-open">app not opening</a>.</li><li>Your console logs are free of errors. To check this, you need to <a href="./ios-testing.html#enable-logging">enable logging</a>.</li></ol><h3 id="deep-links-are-long" tabindex="-1">Deep links are long <a class="header-anchor" href="#deep-links-are-long" aria-label="Permalink to &quot;Deep links are long&quot;">​</a></h3><p>If you find that your Branch Deep Links are long, this is because the app cannot make a connection to the Branch servers.</p><p>However, these long Branch Deep Links will still open the app and pass data.</p><h3 id="deferred-deep-linking-issues" tabindex="-1">Deferred deep linking issues <a class="header-anchor" href="#deferred-deep-linking-issues" aria-label="Permalink to &quot;Deferred deep linking issues&quot;">​</a></h3><p>If deferred deep linking is broken, confirm that you have <a href="./ios-advanced-features.html#nativelink-deferred-deep-linking">enabled</a> NativeLink™.</p><p>Not doing so will cause deferred deep linking to be broken on devices with iOS 15+ installed and Private Relay enabled.</p><p>You can also test your deferred deep linking scenario with these <a href="./ios-testing.html#test-deferred-deep-linking">steps</a>.</p><p>Please note that you must have our <a href="./packaging.html#engagement-essentials-tier">Engagement product</a> to have access to Branch Deferred Deep Linking.</p><h4 id="ios-26-with-safari" tabindex="-1">iOS 26 with Safari <a class="header-anchor" href="#ios-26-with-safari" aria-label="Permalink to &quot;iOS 26 with Safari&quot;">​</a></h4><p>If you are testing on an iOS 26 device with Safari, please note that the user agent OS token gets frozen at <code>18_6</code>.</p><p>In this case, Branch labels iOS 26 devices as iOS 18.6 devices due to the data provided in the user agent. <strong>This prevents a match being made, and breaks deferred deep linking</strong>.</p><p>Branch automatically fixes cases where the os_version is provided by the DSP. For cases where os_version is not available, we <strong>strongly recommend</strong> using <a href="https://help.branch.io/docs/nativelink-deferred-deep-linking" target="_blank" rel="noreferrer">NativeLink™</a>.</p><h3 id="deep-link-routing-issues" tabindex="-1">Deep link routing issues <a class="header-anchor" href="#deep-link-routing-issues" aria-label="Permalink to &quot;Deep link routing issues&quot;">​</a></h3><p>If you&#39;re having issues with deep link routing, confirm that:</p><ol><li>You have followed the appropriate steps in our <a href="./ios-advanced-features.html#navigate-to-content">guide</a> for navigating to content.</li><li>You <a href="./ios-testing.html#test-deep-link-routing">test the routing</a> with the <code>?bnc_validate=true</code> param.</li></ol><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><details><summary>When a user clicks a web-only email link on iOS and they get directed into the app before getting kicked out to web, does Branch still count as app open?</summary><p>Yes, Branch will register an open if a web-only link is clicked, despite the app kicking the user back out to web.</p></details>',29)])])}const g=a(o,[["render",r]]);export{u as __pageData,g as default};
